const fbData = $('Fetch FB Comments').first().json;
const igData = $('Fetch IG Comments').first().json;

const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000);
const newComments = [];

// Process FB comments
if (fbData?.data) {
  for (const post of fbData.data) {
    if (post.comments?.data) {
      for (const comment of post.comments.data) {
        const commentTime = new Date(comment.created_time);
        if (commentTime > twoHoursAgo) {
          newComments.push({
            platform: 'Facebook',
            postId: post.id,
            commentId: comment.id,
            from: comment.from?.name || 'Someone',
            text: comment.message,
            timestamp: comment.created_time
          });
        }
      }
    }
  }
}

// Process IG comments
if (igData?.data) {
  for (const media of igData.data) {
    if (media.comments?.data) {
      for (const comment of media.comments.data) {
        const commentTime = new Date(comment.timestamp);
        if (commentTime > twoHoursAgo) {
          newComments.push({
            platform: 'Instagram',
            postId: media.id,
            commentId: comment.id,
            from: comment.from?.username || 'someone',
            text: comment.text,
            timestamp: comment.timestamp
          });
        }
      }
    }
  }
}

if (newComments.length === 0) {
  return [{ json: { noEngagement: true } }];
}

return newComments.map(c => ({ json: c }));

const items = $input.all();
const originalComment = $('Filter New Comments').first().json;
const results = [];

for (const item of items) {
  let reply = 'Thanks for reaching out!';
  try {
    const content = item.json.choices[0].message.content;
    const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    reply = parsed.reply;
  } catch (e) {}

  results.push({
    json: {
      ...originalComment,
      suggestedReply: reply
    }
  });
}

return results;

